// ========================================
// KONFİGÜRASYON — Takip etmek istediğiniz
// kategorileri ve şehirleri burada ayarlayın
// ========================================

const CONFIG = {
  // Takip edilecek kategoriler (birden fazla seçilebilir)
  // 693 = Araştırma Gör. & Öğretim Gör. & Uzman
  // 672 = Öğretim Üyesi (Prof., Doç., Dr. Öğr. Üyesi)
  // 73  = Tüm Akademik Personel Alımları
  categories: [693, 672],

  // Şehir filtresi (plaka kodları, boş bırakılırsa tüm şehirler)
  // Örnekler: 6=Ankara, 34=İstanbul, 35=İzmir, 16=Bursa
  // Boş dizi [] = tüm şehirler
  cities: [],

  // Sayfa başına maksimum ilan
  maxResults: 50
};

// Her kategori için ayrı bir API request objesi oluştur
const requests = CONFIG.categories.map(txv => {
  const keys = { txv: [txv], currentPage: [1] };

  // Şehir filtresi varsa ekle
  if (CONFIG.cities.length > 0) {
    keys.cty = CONFIG.cities;
  }

  return {
    categoryId: txv,
    requestBody: JSON.stringify({
      keys,
      sorting: 'publish_time desc',
      skipCount: 0,
      maxResultCount: CONFIG.maxResults
    })
  };
});

return requests;

// İlan bilgilerini parse et ve HTML-unsafe karakterleri temizle

const item = $input.item.json;

// HTML-safe escape fonksiyonu
function escapeHtml(text) {
  if (!text) return '';
  return String(text)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

// İlan bilgileri
const adId = item.id;
const adNo = item.adNo || '';
const title = escapeHtml(item.title || '');
const city = escapeHtml(item.addressCityName || '');
const advertiser = escapeHtml(item.advertiserName || '');
const publishDate = item.publishStartDate || '';
const urlStr = item.urlStr || '';
const adSourceName = escapeHtml(item.adSourceName || '');

// adTypeFilters varsa ek bilgileri çek
const adTypeFilters = item.adTypeFilters || [];
const filterParts = [];
adTypeFilters.forEach(f => {
  if (f.key && f.value) {
    filterParts.push(`${escapeHtml(f.key)}: ${escapeHtml(f.value)}`);
  }
});
const filterText = filterParts.join(' | ');

return {
  adId,
  adNo,
  title,
  city,
  advertiser,
  publishDate,
  adSourceName,
  url: `https://www.ilan.gov.tr${urlStr}`,
  filterText,
  cacheKey: `ilan_${adId}`
};

// Workflow static data ile deduplication
const staticData = $getWorkflowStaticData('global');

if (!staticData.seenAds) {
  staticData.seenAds = {};
}

const item = $input.item.json;
const cacheKey = item.cacheKey;

// Bu ilan daha önce görüldü mü?
if (staticData.seenAds[cacheKey]) {
  return [];
}

// Yeni ilan! Kaydet
staticData.seenAds[cacheKey] = {
  seenAt: new Date().toISOString(),
  adNo: item.adNo,
  title: item.title,
  city: item.city,
  advertiser: item.advertiser
};

// Eski kayıtları temizle (500'den fazla olmasın)
const keys = Object.keys(staticData.seenAds);
if (keys.length > 500) {
  const oldestKeys = keys.slice(0, keys.length - 500);
  oldestKeys.forEach(k => delete staticData.seenAds[k]);
}

return item;

const item = $input.item.json;

// Tarihi Türkçe formatla
let tarih = '';
if (item.publishDate) {
  const d = new Date(item.publishDate);
  tarih = d.toLocaleDateString('tr-TR', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric'
  });
}

// --- Telegram Mesajı (HTML) ---
const telegramMsg = [
  `🎓 <b>YENİ AKADEMİK İLAN</b>`,
  ``,
  `📋 <b>İlan No:</b> ${item.adNo}`,
  `🏛️ <b>Kurum:</b> ${item.advertiser}`,
  `📌 <b>Başlık:</b> ${item.title}`,
  `📍 <b>Şehir:</b> ${item.city}`,
  `📅 <b>Yayın Tarihi:</b> ${tarih}`,
  item.adSourceName ? `📰 <b>Kaynak:</b> ${item.adSourceName}` : '',
  item.filterText ? `🔍 <b>Detaylar:</b> ${item.filterText}` : '',
  ``,
  `🔗 <a href="${item.url}">İlanı Görüntüle</a>`
].filter(l => l !== '').join('\n');

// --- Email Mesajı (HTML) ---
const emailHtml = `
<div style="font-family: 'Segoe UI', Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); padding: 20px; border-radius: 12px 12px 0 0;">
    <h2 style="color: white; margin: 0;">🎓 Yeni Akademik İlan</h2>
  </div>
  <div style="background: #f8f9fa; padding: 24px; border-radius: 0 0 12px 12px; border: 1px solid #e9ecef;">
    <table style="width: 100%; border-collapse: collapse;">
      <tr><td style="padding: 8px 0; color: #6c757d;">📋 İlan No</td><td style="padding: 8px 0; font-weight: 600;">${item.adNo}</td></tr>
      <tr><td style="padding: 8px 0; color: #6c757d;">🏛️ Kurum</td><td style="padding: 8px 0; font-weight: 600;">${item.advertiser}</td></tr>
      <tr><td style="padding: 8px 0; color: #6c757d;">📌 Başlık</td><td style="padding: 8px 0; font-weight: 600;">${item.title}</td></tr>
      <tr><td style="padding: 8px 0; color: #6c757d;">📍 Şehir</td><td style="padding: 8px 0; font-weight: 600;">${item.city}</td></tr>
      <tr><td style="padding: 8px 0; color: #6c757d;">📅 Yayın Tarihi</td><td style="padding: 8px 0; font-weight: 600;">${tarih}</td></tr>
      ${item.adSourceName ? `<tr><td style="padding: 8px 0; color: #6c757d;">📰 Kaynak</td><td style="padding: 8px 0; font-weight: 600;">${item.adSourceName}</td></tr>` : ''}
      ${item.filterText ? `<tr><td style="padding: 8px 0; color: #6c757d;">🔍 Detaylar</td><td style="padding: 8px 0; font-weight: 600;">${item.filterText}</td></tr>` : ''}
    </table>
    <div style="margin-top: 20px; text-align: center;">
      <a href="${item.url}" style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 12px 32px; border-radius: 8px; text-decoration: none; font-weight: 600;">İlanı Görüntüle →</a>
    </div>
  </div>
  <p style="text-align: center; color: #adb5bd; font-size: 12px; margin-top: 16px;">ilan.gov.tr Akademik İlan Takip Sistemi</p>
</div>`;

const emailSubject = `🎓 Yeni Akademik İlan: ${item.title.substring(0, 80)}`;

return {
  telegramMessage: telegramMsg,
  emailHtml: emailHtml,
  emailSubject: emailSubject
};

// HTTP Request hata durumunda loglama
const error = $input.item.json;
console.log('ilan.gov.tr API hatası:', JSON.stringify(error));

return {
  errorMessage: `⚠️ ilan.gov.tr API Hatası\n\nWorkflow çalıştı ancak API yanıt vermedi veya hata döndü.\nLütfen n8n execution log'unu kontrol edin.\n\nZaman: ${new Date().toLocaleString('tr-TR')}`,
  errorTimestamp: new Date().toISOString()
};

// Haftalık özet raporu oluştur
const staticData = $getWorkflowStaticData('global');
const seenAds = staticData.seenAds || {};

// Son 7 gündeki ilanları filtrele
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const weeklyAds = Object.values(seenAds).filter(ad => {
  const seenDate = new Date(ad.seenAt);
  return seenDate >= weekAgo;
});

// Şehir bazlı istatistik
const cityStats = {};
weeklyAds.forEach(ad => {
  const city = ad.city || 'Bilinmiyor';
  cityStats[city] = (cityStats[city] || 0) + 1;
});

// Kurum bazlı istatistik
const instStats = {};
weeklyAds.forEach(ad => {
  const inst = ad.advertiser || 'Bilinmiyor';
  instStats[inst] = (instStats[inst] || 0) + 1;
});

// Şehir tablosu oluştur
const citySorted = Object.entries(cityStats)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10);
const cityLines = citySorted.map(([c, n]) => `  • ${c}: ${n} ilan`).join('\n');

// Kurum tablosu
const instSorted = Object.entries(instStats)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10);
const instLines = instSorted.map(([i, n]) => `  • ${i}: ${n} ilan`).join('\n');

// Tarih formatla
const formatDate = (d) => d.toLocaleDateString('tr-TR', {
  day: '2-digit', month: '2-digit', year: 'numeric'
});

// --- Telegram Mesajı ---
const telegramMsg = [
  `📊 <b>HAFTALIK AKADEMİK İLAN ÖZETİ</b>`,
  `📅 ${formatDate(weekAgo)} — ${formatDate(now)}`,
  ``,
  `📈 <b>Toplam Yeni İlan:</b> ${weeklyAds.length}`,
  ``,
  `🏙️ <b>Şehirlere Göre:</b>`,
  cityLines || '  Veri yok',
  ``,
  `🏛️ <b>Kurumlara Göre (İlk 10):</b>`,
  instLines || '  Veri yok'
].join('\n');

// --- Email HTML ---
const cityRows = citySorted.map(([c, n]) =>
  `<tr><td style="padding:6px 12px;border-bottom:1px solid #eee;">${c}</td><td style="padding:6px 12px;border-bottom:1px solid #eee;text-align:center;font-weight:600;">${n}</td></tr>`
).join('');

const instRows = instSorted.map(([i, n]) =>
  `<tr><td style="padding:6px 12px;border-bottom:1px solid #eee;">${i}</td><td style="padding:6px 12px;border-bottom:1px solid #eee;text-align:center;font-weight:600;">${n}</td></tr>`
).join('');

const emailHtml = `
<div style="font-family:'Segoe UI',Arial,sans-serif;max-width:600px;margin:0 auto;">
  <div style="background:linear-gradient(135deg,#11998e 0%,#38ef7d 100%);padding:20px;border-radius:12px 12px 0 0;">
    <h2 style="color:white;margin:0;">📊 Haftalık Akademik İlan Özeti</h2>
    <p style="color:rgba(255,255,255,0.85);margin:8px 0 0;">${formatDate(weekAgo)} — ${formatDate(now)}</p>
  </div>
  <div style="background:#f8f9fa;padding:24px;border-radius:0 0 12px 12px;border:1px solid #e9ecef;">
    <div style="text-align:center;margin-bottom:20px;">
      <span style="font-size:48px;font-weight:700;color:#11998e;">${weeklyAds.length}</span>
      <br><span style="color:#6c757d;">yeni ilan bu hafta</span>
    </div>
    <h3 style="color:#333;margin:16px 0 8px;">🏙️ Şehirlere Göre</h3>
    <table style="width:100%;border-collapse:collapse;">
      <tr style="background:#e9ecef;"><th style="padding:8px 12px;text-align:left;">Şehir</th><th style="padding:8px 12px;text-align:center;">İlan</th></tr>
      ${cityRows || '<tr><td colspan="2" style="padding:8px;color:#aaa;">Veri yok</td></tr>'}
    </table>
    <h3 style="color:#333;margin:20px 0 8px;">🏛️ Kurumlara Göre (İlk 10)</h3>
    <table style="width:100%;border-collapse:collapse;">
      <tr style="background:#e9ecef;"><th style="padding:8px 12px;text-align:left;">Kurum</th><th style="padding:8px 12px;text-align:center;">İlan</th></tr>
      ${instRows || '<tr><td colspan="2" style="padding:8px;color:#aaa;">Veri yok</td></tr>'}
    </table>
  </div>
  <p style="text-align:center;color:#adb5bd;font-size:12px;margin-top:16px;">ilan.gov.tr Akademik İlan Takip Sistemi</p>
</div>`;

return {
  telegramMessage: telegramMsg,
  emailHtml: emailHtml,
  emailSubject: `📊 Haftalık Akademik İlan Özeti — ${weeklyAds.length} yeni ilan (${formatDate(weekAgo)} - ${formatDate(now)})`
};
